parameters.jsCode:
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const allTranscripts = response?.data?.transcripts || [];

if (allTranscripts.length === 0) {
  return [{
    json: {
      hasTranscripts: false,
      message: 'No transcripts in Fireflies account',
      weekStart: config.weekStart,
      weekEnd: config.weekEnd,
      slackChannel: config.slackChannel,
      companyName: config.companyName
    }
  }];
}

// Filter last 7 days
const sevenDaysAgo = config.sevenDaysAgoMs;
const recent = allTranscripts.filter(t => (t.date || 0) >= sevenDaysAgo);

if (recent.length === 0) {
  return [{
    json: {
      hasTranscripts: false,
      message: 'No meetings in last 7 days',
      weekStart: config.weekStart,
      weekEnd: config.weekEnd,
      slackChannel: config.slackChannel,
      companyName: config.companyName
    }
  }];
}

// Return one item per transcript for loop processing
return recent.map(t => ({
  json: {
    hasTranscripts: true,
    transcriptId: t.id,
    transcriptTitle: t.title || 'Untitled Meeting',
    transcriptDate: t.date
      ? new Date(t.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
      : 'Unknown',
    durationMin: Math.round((t.duration || 0) / 60),
    participants: (t.participants || []).join(', ') || 'Unknown',
    transcriptUrl: t.transcript_url || 'Not available',
    totalMeetings: recent.length,
    firefliesApiKey: config.firefliesApiKey,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    slackChannel: config.slackChannel,
    slackAlertChannel: config.slackAlertChannel,
    companyName: config.companyName,
    weekStart: config.weekStart,
    weekEnd: config.weekEnd
  }
}));

parameters.jsonBody:
={
  "query": "query GetTranscript($id: String!) { transcript(id: $id) { id title date duration participants transcript_url sentences { speaker_name text } summary { overview keywords action_items } analytics { sentiments { positive_pct neutral_pct negative_pct } } } }",
  "variables": {
    "id": "{{ $json.transcriptId }}"
  }
}

parameters.jsCode:
const response = $input.first().json;
const prev = $('4. Code — Filter Last 7 Days').item.json;

const transcript = response?.data?.transcript;
if (!transcript || !transcript.id) {
  return [{
    json: {
      hasData: false,
      transcriptId: prev.transcriptId,
      transcriptTitle: prev.transcriptTitle,
      sheetId: prev.sheetId,
      sheetName: prev.sheetName,
      slackChannel: prev.slackChannel,
      slackAlertChannel: prev.slackAlertChannel,
      companyName: prev.companyName,
      weekStart: prev.weekStart,
      weekEnd: prev.weekEnd,
      totalMeetings: prev.totalMeetings
    }
  }];
}

// Build readable transcript excerpt (max 4000 chars)
const sentences = transcript.sentences || [];
let transcriptText = '';
sentences.forEach(s => {
  const speaker = s.speaker_name || 'Speaker';
  const text = (s.text || '').trim();
  if (text) transcriptText += speaker + ': ' + text + '\n';
});
const transcriptExcerpt = transcriptText.substring(0, 4000);

// Fireflies built-in sentiment scores
const sentiments = transcript.analytics?.sentiments || {};
const positivePct = Math.round(sentiments.positive_pct || 0);
const neutralPct = Math.round(sentiments.neutral_pct || 0);
const negativePct = Math.round(sentiments.negative_pct || 0);

// Compute composite sentiment score (0-100)
const sentimentScore = Math.round((positivePct * 1) + (neutralPct * 0.5) - (negativePct * 0.5));

// Determine label from Fireflies scores
let sentimentLabel = 'Neutral';
if (positivePct >= 60) sentimentLabel = 'Positive';
else if (negativePct >= 35) sentimentLabel = 'Negative';
else if (positivePct >= 45) sentimentLabel = 'Mostly Positive';
else if (negativePct >= 25) sentimentLabel = 'Mostly Negative';

// Extract client name from meeting title
const title = transcript.title || 'Untitled Meeting';
let clientName = 'Unknown Client';
const patterns = [
  /call with (.+?)(?:\s*[-–|]|$)/i,
  /(.+?)\s*(?:call|meeting|review|sync|check.?in|catchup|catch.?up)/i,
  /(.+?)\s*[-–|]/i
];
for (const pattern of patterns) {
  const match = title.match(pattern);
  if (match && match[1] && match[1].trim().length > 1) {
    clientName = match[1].trim();
    break;
  }
}
if (clientName === 'Unknown Client' && title.length < 40) {
  clientName = title;
}

const summary = transcript.summary || {};
const overview = (summary.overview || '').substring(0, 600);
const keywords = (summary.keywords || []).slice(0, 8).join(', ');
const actionItems = (summary.action_items || []).slice(0, 5).join(' | ');

const meetingDate = transcript.date
  ? new Date(transcript.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : prev.transcriptDate;

return [{
  json: {
    hasData: true,
    transcriptId: transcript.id,
    transcriptTitle: title,
    clientName,
    meetingDate,
    durationMin: Math.round((transcript.duration || 0) / 60) || prev.durationMin,
    participants: (transcript.participants || []).join(', ') || prev.participants,
    transcriptUrl: transcript.transcript_url || prev.transcriptUrl,
    transcriptExcerpt,
    overview,
    keywords,
    actionItems,
    positivePct,
    neutralPct,
    negativePct,
    sentimentScore,
    sentimentLabel,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    slackChannel: prev.slackChannel,
    slackAlertChannel: prev.slackAlertChannel,
    companyName: prev.companyName,
    weekStart: prev.weekStart,
    weekEnd: prev.weekEnd,
    totalMeetings: prev.totalMeetings
  }
}];

parameters.text:
=You are a client relationship analyst at {{ $json.companyName }}.

Analyze this client meeting and provide intelligence about client health and relationship status.

MEETING DETAILS:
Client: {{ $json.clientName }}
Meeting Title: {{ $json.transcriptTitle }}
Date: {{ $json.meetingDate }}
Duration: {{ $json.durationMin }} minutes
Participants: {{ $json.participants }}

FIREFLIES SENTIMENT SCORES:
Positive: {{ $json.positivePct }}%
Neutral: {{ $json.neutralPct }}%
Negative: {{ $json.negativePct }}%
Overall Label: {{ $json.sentimentLabel }}

MEETING OVERVIEW:
{{ $json.overview }}

KEYWORDS: {{ $json.keywords }}

ACTION ITEMS: {{ $json.actionItems }}

TRANSCRIPT EXCERPT:
{{ $json.transcriptExcerpt }}

Return ONLY a valid JSON object with exactly these 4 fields. No extra text. No markdown. No backticks.

gptAnalysis — 2 to 3 plain text sentences explaining WHY this meeting had this sentiment. What specifically was discussed that was positive, neutral, or negative? Reference actual content from the transcript. Under 80 words.

churnRisk — One of exactly these values: Low OR Medium OR High OR Critical
Low = client is happy, engaged, expanding
Medium = some concerns raised but relationship is stable
High = clear frustration, unresolved issues, or signs of disengagement
Critical = client threatened to leave, expressed serious anger, or is clearly about to churn

recommendedAction — One specific action the account manager should take within 48 hours. Be concrete. Start with a verb. Under 20 words. Plain text only.

keyQuote — The single most important sentence from this meeting — positive or negative — that best captures the client mood. Under 25 words. Plain text. If no clear quote found write: No standout quote identified.

