parameters.jsCode:
// Combine AI output with meeting data for Sheets + Slack
const aiOutput = $input.first().json.output;
const meetingData = $('8. Code — Extract Sentiment Data').item.json;

const gptAnalysis = aiOutput?.gptAnalysis || 'Analysis not available';
const churnRisk = aiOutput?.churnRisk || 'Unknown';
const recommendedAction = aiOutput?.recommendedAction || 'Review meeting manually';
const keyQuote = aiOutput?.keyQuote || 'No standout quote identified';

// Determine if this needs an urgent Slack alert
const isNegative = ['Negative', 'Mostly Negative'].includes(meetingData.sentimentLabel);
const isHighRisk = ['High', 'Critical'].includes(churnRisk);
const needsAlert = isNegative || isHighRisk;

// Emoji for sentiment label
const sentimentEmoji = {
  'Positive': '🟢',
  'Mostly Positive': '🟡',
  'Neutral': '⚪',
  'Mostly Negative': '🟠',
  'Negative': '🔴'
}[meetingData.sentimentLabel] || '⚪';

// Emoji for churn risk
const riskEmoji = {
  'Low': '✅',
  'Medium': '⚠️',
  'High': '🚨',
  'Critical': '🆘'
}[churnRisk] || '⚠️';

const loggedAt = new Date().toISOString().replace('T', ' ').substring(0, 16);

return [{
  json: {
    weekLabel: meetingData.weekStart + ' to ' + meetingData.weekEnd,
    meetingDate: meetingData.meetingDate,
    meetingTitle: meetingData.transcriptTitle,
    clientName: meetingData.clientName,
    durationMin: meetingData.durationMin,
    participants: meetingData.participants,
    sentimentScore: meetingData.sentimentScore,
    sentimentLabel: meetingData.sentimentLabel,
    positivePct: meetingData.positivePct,
    negativePct: meetingData.negativePct,
    gptAnalysis,
    churnRisk,
    recommendedAction,
    transcriptUrl: meetingData.transcriptUrl,
    loggedAt,
    needsAlert,
    sentimentEmoji,
    riskEmoji,
    keyQuote,
    sheetId: meetingData.sheetId,
    sheetName: meetingData.sheetName,
    slackChannel: meetingData.slackChannel,
    slackAlertChannel: meetingData.slackAlertChannel,
    companyName: meetingData.companyName,
    weekStart: meetingData.weekStart,
    weekEnd: meetingData.weekEnd,
    totalMeetings: meetingData.totalMeetings
  }
}];

